import{_ as s,a as t,b as e}from"./chunks/dispatch.B8uN1392.js";import{_ as a,o as r,c as g,a1 as h}from"./chunks/framework.C-iSDJMk.js";const n="/WoW_Guides/assets/outlaw.B7h3ff6C.png",o="data:image/jpeg;base64,",E="data:image/jpeg;base64,",i="data:image/jpeg;base64,",B="data:image/jpeg;base64,",l="data:image/jpeg;base64,",Q="data:image/jpeg;base64,",p="data:image/jpeg;base64,",H="data:image/jpeg;base64,",c="data:image/jpeg;base64,",w="data:image/jpeg;base64,",d="data:image/jpeg;base64,",x="data:image/jpeg;base64,",I=JSON.parse('{"title":"暴徒盜賊12.0","description":"","frontmatter":{},"headers":[],"relativePath":"WoW/classes/Outlaw_Rogue.md","filePath":"WoW/classes/Outlaw_Rogue.md"}'),U={name:"WoW/classes/Outlaw_Rogue.md"};function R(C,A,D,m,S,G){return r(),g("div",null,[...A[0]||(A[0]=[h('<div class="game-grid-container"><a href="/WoW_Guides/WoW/classes/Assassination_Rogue.html" class="game-card"><div class="card-icon"><img src="'+s+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"></div><div class="card-title">刺殺盜賊筆記</div><div class="card-desc"></div></a><a href="/WoW_Guides/WoW/classes/Subtlety_Rogue.html" class="game-card"><div class="card-icon"><img src="'+t+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"></div><div class="card-title">敏銳盜賊筆記</div><div class="card-desc"></div></a><a href="/WoW_Guides/WoW/classes/Outlaw_Rogue.html" class="game-card"><div class="card-icon"><img src="'+e+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"></div><div class="card-title">暴徒盜賊筆記</div><div class="card-desc"></div></a></div><h1 id="暴徒盜賊12-0" tabindex="-1">暴徒盜賊12.0 <a class="header-anchor" href="#暴徒盜賊12-0" aria-label="Permalink to &quot;暴徒盜賊12.0&quot;">​</a></h1><p><img src="'+n+'" alt="outlaw"> 最後編輯時間: 2026/07/14</p><h2 id="簡介" tabindex="-1">簡介 <a class="header-anchor" href="#簡介" aria-label="Permalink to &quot;簡介&quot;">​</a></h2><p>暴徒目前的強度大概是T1級別。雖然和T0專精有差距，但絕對稱不上弱勢，尤其在特定隊伍組成的情況下還是有一定強度。</p><p>上手難度高，初期熟悉時容易因手忙腳亂，傷害打不出來而有挫折。 是個沒有固定循環、高操作頻率的專精，戰鬥時的核心就是一直在刷技能。 需要腦袋足夠清晰，大招期間每0.8秒從將近10個技能裡判斷打什麼比較好，很吃各種臨場經驗。</p><p><strong>優點</strong>: 高機動性、生存能力佳、平傷高、面對單體和多目標的變化不大</p><p><strong>缺點</strong>: 操作複雜、團隊功能性弱、爆發傷害普通、吃運氣</p><h2 id="天賦" tabindex="-1">天賦 <a class="header-anchor" href="#天賦" aria-label="Permalink to &quot;天賦&quot;">​</a></h2><p>單體天賦和aoe天賦幾乎沒有變化，甚至可以直接無腦使用aoe天賦到底。 因為即便把aoe用的點數拿去點其他天賦，對單體也沒什麼明顯的提升，更何況現在很少有真的純單體的戰鬥。 因此本篇會直接以aoe天賦來說明，新手可以把天賦<strong>隱匿</strong>替換成<strong>死亡謊言</strong>。</p><ul><li>單體天賦代碼: CQQAphyM11FofNMFa1K3vFEDUCgx2MYmZmZmtZmZMjxsAzMbTLD2mBAAAAAYbbmZGmZmZGzMz2AAAAYGDYwsNLmZmRzMbMLssNtwGDwMzMzAD</li><li>aoe天賦代碼: CQQAphyM11FofNMFa1K3vFEDUCgx2MYmZmZmtZmZMzMzsAmZbaZw2MAAAAAgZbbmZGmZmZGzMz2AAAAwYADmtZxMzMamZjZhltpF2YAmZmZGYA</li></ul><h2 id="技能" tabindex="-1">技能 <a class="header-anchor" href="#技能" aria-label="Permalink to &quot;技能&quot;">​</a></h2><h3 id="基礎循環" tabindex="-1">基礎循環 <a class="header-anchor" href="#基礎循環" aria-label="Permalink to &quot;基礎循環&quot;">​</a></h3><p>首先塗好毒藥，通常是塗 <span class="tooltip"><strong>速效毒藥</strong><span class="tooltiptext"><img src="'+o+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>速效毒藥</strong><br><em>瞬發</em><br> 在你的武器上塗抹猛烈毒藥，持續1小時。每次攻擊都有30%的機率使敵人中毒，立即造成自然傷害。 </span></span> 和 <span class="tooltip"><strong>萎縮毒藥</strong><span class="tooltiptext"><img src="'+E+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>萎縮毒藥</strong><br><em>瞬發</em><br> 在你的武器上塗抹非猛烈毒藥，持續1小時。每次攻擊有30%的機率使敵人中毒，使其造成的傷害降低3%，持續10秒。 </span></span> ，接著最好進 <span class="tooltip"><strong>潛行</strong><span class="tooltiptext"><img src="'+t+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>潛行</strong><br><em>瞬發</em><br> 潛入暗影之中，使你能夠在不被發現的情況下追蹤敵人，直到主動取消。 </span></span> 。</p><p>戰鬥過程使用技能集連擊點至<strong>6個</strong>以上，再使用終結技。 終結技至少要有1個連擊點才能使用，並且消耗的連擊點多寡，會影響效果強度(如: 傷害、持續時間)。</p><ul><li><img src="'+i+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>邪惡攻擊</strong>: 最基本的連擊技能，獎勵1個連擊點。</li><li><img src="'+e+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>抹殺</strong>: 最基本的終結技。</li><li><img src="'+B+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>手槍射擊</strong>: 遠程連擊技，獎勵1個連擊點。只有在發亮時使用，可獎勵4個連擊點。</li><li><img src="'+l+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>正中眉心</strong>: 遠程技能，效益最高的終結技。CD結束就用。</li><li><img src="'+Q+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>劍刃亂舞</strong>: 使自身單體攻擊能以百分比複製至周圍目標。2目標以上且身上沒有劍刃亂舞時，CD結束就用。</li></ul><p>連擊技優先級: <strong>劍刃亂舞</strong> &gt; <strong>高亮手槍</strong> &gt; <strong>邪惡攻擊</strong></p><p>終結技優先級: <strong>正中眉心</strong> &gt; <strong>抹殺</strong></p><details class="details custom-block"><summary>優化細節</summary><p><strong>切割</strong>也是終結技，效果是增加攻速。 被動<strong>急起直追</strong>使得施放<strong>抹殺</strong>時，自動賦予<strong>切割</strong>效果。 因此若身上還沒有<strong>切割</strong>時，通常進戰鬥後的第一個終結技會使用<strong>抹殺</strong>。</p><p>由於天賦因素，<strong>劍刃亂舞</strong>每命中1個目標也能獎勵1個連擊點，根據大數據模擬，面對4目標以上且身上已有<strong>劍刃亂舞</strong>時，仍可作為獎勵連擊點的技能卡CD用。</p></details><h3 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h3><ul><li><img src="'+p+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>能量刺激</strong>: 最重要的大招之一，增加攻速與能量回復速度、提高能量上限。CD結束就用。</li><li><img src="'+H+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>命運之骰</strong>: 隨機賦予四階效果中的其中一階。身上沒有骰子buff時，CD結束就用。</li></ul><details class="details custom-block"><summary>優化細節</summary><p>如果當前戰鬥很快就要結束，<strong>能量刺激</strong>可以扣著不用。 因為天賦關係，施放<strong>能量刺激</strong>時會充滿連擊點。 <strong>能量刺激</strong>還有個沒有明寫的效果，施放期間gdc暫時會受到加速屬性影響，最多減至0.8秒。 以盜賊而言，從1秒降至0.8秒，加速要疊到將近25%，這也是為什麼暴徒需要優先疊加速的原因。</p><p>由於天賦使得<strong>能量刺激</strong>會賦予<strong>灌鉛骰子</strong>，下一次<strong>命運之骰</strong>必定獲得二階以上的buff，加上<strong>命運之骰</strong>的第一階buff效果不強，因此身上若是一階效果就再骰一次。 <strong>命運之骰</strong>每一階效果骰到的機率分別是55%(一階)、30%(二階)、10%(三階)與5%(四階)，並且具向下兼容(ex: 若骰到二階，同時擁有一階的效果)。 二階骰子buff會使<strong>邪惡攻擊</strong>額外獎勵1個連擊點，而<strong>高亮手槍</strong>會獎勵4個連擊點，因此:</p><ul><li>0~3星時，使用<strong>高亮手槍</strong></li><li>4或5星時，使用<strong>邪惡攻擊</strong></li><li>6、7星時，使用終結技</li></ul></details><h3 id="cd技能" tabindex="-1">CD技能 <a class="header-anchor" href="#cd技能" aria-label="Permalink to &quot;CD技能&quot;">​</a></h3><ul><li><img src="'+c+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>劍刃猛攻</strong>: 不消耗資源的技能，還能提供微量能量回復，會位移至目標周圍。CD結束就用。</li><li><img src="'+w+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>狂舞殘殺</strong>: 引導型終結技，傷害一般，會在引導期間逐漸返還連擊點。CD結束就用。</li><li><img src="'+d+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>骰個不停</strong>: 使身上的骰子buff時間延長30秒。若身上骰子buff為三階以上，CD結束就用。</li><li><img src="'+x+'" style="width:30px;display:inline-block;vertical-align:middle;margin-right:8px;"><strong>備戰</strong>: 立即刷新<strong>能量刺激</strong>、<strong>狂舞殘殺</strong>、<strong>劍刃猛攻</strong>、<strong>正中眉心</strong>與<strong>劍刃亂舞</strong>。當<strong>能量刺激</strong>、<strong>劍刃猛攻</strong>與<strong>正中眉心</strong>CD時使用。</li></ul><p>連擊技優先級: <strong>劍刃亂舞</strong> &gt; <strong>高亮手槍</strong> &gt; <strong>邪惡攻擊</strong></p><p>終結技優先級: <strong>正中眉心</strong> &gt; <strong>狂舞殘殺</strong> &gt; <strong>抹殺</strong></p><details class="details custom-block"><summary>優化細節</summary><p>2目標以上時，<strong>劍刃猛攻</strong>在身上有<strong>劍刃亂舞</strong>的情況下可增傷。</p><p><strong>狂舞殘殺</strong>能給多個目標上debuff，並且可以利用引導期間回復能量。 由於<strong>狂舞殘殺</strong>傷害普通，雖然是終結技但建議5個連擊點即可施放，並且建議在連擊點返還滿時自行中斷。 引導<strong>狂舞殘殺</strong>期間，可使用減傷技能(如: <strong>佯攻</strong>、<strong>閃避</strong>等)以及位移技能<strong>繩鉤</strong>。</p><p><strong>骰個不停</strong>的CD看似很長，但可受被動<strong>不息之刃</strong>影響，若循環基礎打得好且運氣也不錯的情況下，實際上CD大概120~150秒。</p><p><strong>備戰</strong>不受<strong>不息之刃</strong>影響，CD就是4分鐘，若<strong>能量刺激</strong>CD快小於1分鐘，可以扣著等待下次開啟<strong>能量刺激</strong>後再用。 若<strong>能量刺激</strong>CD小於40秒，<strong>正中眉心</strong>建議扣著不用，但如果<strong>備戰</strong>能使用則可以無視。</p></details><h3 id="簡易開場" tabindex="-1">簡易開場 <a class="header-anchor" href="#簡易開場" aria-label="Permalink to &quot;簡易開場&quot;">​</a></h3><ul><li><strong>能量刺激</strong></li><li><strong>命運之骰</strong></li><li><strong>骰個不停</strong>(若骰子buff為三階以上) + 爆發藥水 + 飾品主動技</li><li><strong>抹殺</strong></li><li><strong>劍刃亂舞</strong>(若2目標以上)</li><li><strong>劍刃猛攻</strong></li><li>按照技能優先級施放</li></ul><h2 id="資料參考" tabindex="-1">資料參考 <a class="header-anchor" href="#資料參考" aria-label="Permalink to &quot;資料參考&quot;">​</a></h2><ul><li><a href="https://www.wowhead.com/" target="_blank" rel="noreferrer">Wowhead</a></li></ul>',31)])])}const u=a(U,[["render",R]]);export{I as __pageData,u as default};
